const smData = $('State Machine Lead').first().json;
const ts = new Date().toISOString().replace('T',' ').substring(0,19);

// For actions that have a subsequent dedicated session update (e.g. Store AI Questions,
// Update Session Score), skip the generic Update Session by using a bogus sessionName.
// This node runs AFTER those action branches complete, so the real session is already
// correctly set. Using a bogus name causes a harmless 404 (ignored by neverError:true).
const deferredActions = ['generate_ai_questions', 'generate_vendor_questions', 'calculate_vendor_score'];
const sessionName = deferredActions.includes(smData.action)
  ? 'SKIP_ALREADY_UPDATED'
  : smData.sessionName;
const isNew = deferredActions.includes(smData.action)
  ? false
  : !smData.sessionName;

return [{
  json: {
    phone: smData.phone,
    nextStep: smData.nextStep,
    sessionData: smData.sessionData,
    sessionName,
    isNew,
    now: ts
  }
}];

const smData = $('State Machine Lead').first().json;
const countResult = $input.first().json;

const actionData = JSON.parse(smData.actionData || '{}');
const existingCount = countResult?.data?.length || 0;
const newIndex = String(existingCount + 1).padStart(4, '0');
const year = new Date().getFullYear();
const lead_id = `LEAD-FREE-${year}-${newIndex}`;

const description = actionData.lead_description || '';
const title = description.substring(0, 50) + (description.length > 50 ? '...' : '');

const aiQualification = {};
for (let i = 1; i <= 6; i++) {
  if (actionData[`ai_question_${i}`]) aiQualification[`question_${i}`] = actionData[`ai_question_${i}`];
  if (actionData[`ai_answer_${i}`]) aiQualification[`answer_${i}`] = actionData[`ai_answer_${i}`];
}

const ts = new Date().toISOString().replace('T',' ').substring(0,19);

const payload = {
  doctype: 'RIFAH Lead',
  lead_id,
  member_id: actionData.member_id || '',
  member_name: actionData.member_name || '',
  member_phone: actionData.phone || smData.phone,
  tier: 'FREE',
  lead_type: actionData.lead_type || '',
  title,
  description,
  location: actionData.lead_location || '',
  urgency: actionData.lead_urgency || '',
  budget: actionData.lead_budget || '',
  ai_qualification: JSON.stringify(aiQualification),
  status: 'Pending Review',
  posted_to_groups: '[]',
  interested_vendors: '[]',
  connection_made: 0,
  created_at: ts
};

return [{ json: { payload, lead_id, member_phone: actionData.phone || smData.phone, member_name: actionData.member_name || '', lead_type: actionData.lead_type || '', location: actionData.lead_location || '', urgency: actionData.lead_urgency || '', budget: actionData.lead_budget || '', description } }];

