const response = $input.first().json;
const smData = $('State Machine Lead').first().json;

let questions = [];
try {
  const content = response.choices[0].message.content;
  let parsed;
  try { parsed = JSON.parse(content); }
  catch(e) {
    const cleaned = content.replace(/```json\n?/g,'').replace(/```\n?/g,'').trim();
    parsed = JSON.parse(cleaned);
  }
  questions = parsed.questions || [];
  if (!questions.length) throw new Error('empty');
} catch(e) {
  // Fallback by lead type
  const fallback = {
    'BUY': ['What are the exact specifications?','What quantity do you need per order?','Any quality certifications required?','What is your delivery timeline?','Any special requirements or customization?'],
    'SELL': ['What are the product specifications?','What is your production capacity per month?','Do you have any certifications?','What is your delivery capability?','What makes your product unique?'],
    'SERVICE NEED': ['What is the exact scope of work?','What is the project timeline?','What level of expertise is needed?','What are the deliverables?','Any specific tools or technologies required?'],
    'SERVICE OFFER': ['What specific services do you provide?','What is your capacity per month?','What certifications do you have?','What is your typical project timeline?','What industries have you worked with?']
  };
  const actionData = JSON.parse(smData.actionData || '{}');
  questions = fallback[actionData.lead_type] || fallback['BUY'];
}

const actionData = JSON.parse(smData.actionData || '{}');
const q1 = questions[0] || 'Please provide more details about your requirement';

return [{ json: {
  questions,
  q1,
  totalQuestions: questions.length,
  phone: smData.phone,
  sessionName: smData.sessionName,
  sessionData: smData.sessionData,
  actionData: smData.actionData,
  firstQuestion: `🤖 *AI Assistant*\n\nGreat! I need a few more details to find you the best matches.\n\nI'll ask ${questions.length} quick question${questions.length !== 1 ? 's' : ''}...\n\n*Question 1 of ${questions.length}:*\n${q1}`
}}];

