const leadResult = $('Get Lead for Vendor').first().json;
const vendorResult = $input.first().json;
const smData = $('State Machine Lead').first().json;

const leads = leadResult?.data || [];
const lead = leads.length > 0 ? leads[0] : null;

const vendors = vendorResult?.data || [];
const vendor = vendors.length > 0 ? vendors[0] : null;

const phone = smData.phone;
const actionData = JSON.parse(smData.actionData || '{}');
const lead_id = actionData.lead_id || '';

let introMsg = '';
if (!lead) {
  introMsg = `❌ Lead not found: *${lead_id}*\n\nThis lead may have expired or been removed. Please check the lead ID and try again.`;
} else if (lead.status === 'Closed' || lead.status === 'Cancelled') {
  introMsg = `⚠️ This lead is no longer active.\n\nLead *${lead_id}* has been ${lead.status.toLowerCase()}.`;
} else {
  const tierBadge = lead.tier === 'PREM' ? '⭐ PREMIUM' : '🟢 FREE';
  introMsg = `📋 *Lead Details*\n\n🆔 *${lead.lead_id}* ${tierBadge}\n📌 *Type:* ${lead.lead_type}\n📝 *Requirement:* ${lead.description}\n\n📍 *Location:* ${lead.location}\n⏰ *Urgency:* ${lead.urgency}\n💰 *Budget:* ${lead.budget || 'Not specified'}\n\n━━━━━━━━━━━━━━━━━━━━\n*Are you interested in this lead?*\n\nReply *YES* to start vendor qualification\nReply *NO* to skip`;
}

return [{
  json: {
    lead,
    vendor,
    phone,
    lead_id,
    introMsg,
    sessionName: smData.sessionName,
    sessionData: smData.sessionData
  }
}];

