const smData = $('State Machine Lead').first().json;
const actionData = JSON.parse(smData.actionData || '{}');

// Scores: Q1 can supply (25), Q2 certification (20), Q3 timeline (20), Q4 price (10), Q5 extra (15), Q6 experience (10)
let score = 0;

const a1 = (actionData.vendor_answer_1 || '').toUpperCase();
const a2 = (actionData.vendor_answer_2 || '').toUpperCase();
const a3 = actionData.vendor_answer_3 || '';
const a4 = actionData.vendor_answer_4 || '';
const a5 = (actionData.vendor_answer_5 || '').toUpperCase();
const a6 = (actionData.vendor_answer_6 || '').toUpperCase();
const urgency = actionData.lead_urgency || 'FLEXIBLE';

if (a1.includes('YES')) score += 25;
if (a2.includes('YES')) score += 20;

// Timeline check
const urgencyDays = { 'URGENT':3,'THIS WEEK':7,'THIS MONTH':30,'FLEXIBLE':60 }[urgency] || 30;
const dayMatch = a3.match(/(\d+)\s*days?/i);
const weekMatch = a3.match(/(\d+)\s*weeks?/i);
const monthMatch = a3.match(/(\d+)\s*months?/i);
let timeline = 0;
if (a3.toLowerCase().includes('immediate') || a3.toLowerCase().includes('same day')) timeline = 1;
else if (dayMatch) timeline = parseInt(dayMatch[1]);
else if (weekMatch) timeline = parseInt(weekMatch[1]) * 7;
else if (monthMatch) timeline = parseInt(monthMatch[1]) * 30;
if (timeline > 0 && timeline <= urgencyDays) score += 20;
else if (timeline === 0) score += 10; // partial credit for given but unparseable timeline

if (a5.includes('YES')) score += 15;
if (a6.includes('YES')) score += 10;

const scoreEmoji = score >= 80 ? '🌟🌟🌟' : score >= 70 ? '🌟🌟' : score >= 50 ? '🌟' : '⚠️';
const recommendation = score >= 70 ? '🌟 *This looks like an excellent match!*' : score >= 50 ? '✅ *This could be a good fit.*' : '⚠️ *Match score is low. Consider carefully before proceeding.*';

const vqs = actionData.vendor_questions || [];
const summaryLines = [];
for (let i = 1; i <= 6; i++) {
  const q = vqs[i-1];
  const qText = typeof q === 'object' ? q.q : (q || '');
  const a = actionData[`vendor_answer_${i}`] || '-';
  if (qText) summaryLines.push(`• ${qText.split('?')[0]}: ${a}`);
}

const scoreMsg = `📊 *Match Analysis Complete*\n\nBased on your answers:\n${summaryLines.join('\n')}\n\n*Compatibility Score:* ${score}/100 ${scoreEmoji}\n\n${recommendation}\n\nWould you like to submit your interest to the buyer?\n\nReply *SUBMIT* or *CANCEL*`;

return [{ json: {
  score,
  scoreMsg,
  phone: smData.phone,
  sessionName: smData.sessionName,
  sessionData: JSON.stringify({ ...actionData, compatibility_score: score }),
  lead_id: actionData.lead_id,
  vendor_id: actionData.vendor_id,
  vendor_name: actionData.vendor_name,
  vendor_phone: smData.phone
}}];

